<?php
 namespace League\CommonMark\Block\Element; use League\CommonMark\ContextInterface; use League\CommonMark\Cursor; class ListBlock extends AbstractBlock { const TYPE_BULLET = 'bullet'; const TYPE_ORDERED = 'ordered'; const TYPE_UNORDERED = self::TYPE_BULLET; protected $tight = false; protected $listData; public function __construct(ListData $listData) { $this->listData = $listData; } public function getListData(): ListData { return $this->listData; } public function endsWithBlankLine(): bool { if ($this->lastLineBlank) { return true; } if ($this->hasChildren()) { return $this->lastChild() instanceof AbstractBlock && $this->lastChild()->endsWithBlankLine(); } return false; } public function canContain(AbstractBlock $block): bool { return $block instanceof ListItem; } public function isCode(): bool { return false; } public function matchesNextLine(Cursor $cursor): bool { return true; } public function finalize(ContextInterface $context, int $endLineNumber) { parent::finalize($context, $endLineNumber); $this->tight = true; foreach ($this->children() as $item) { if (!($item instanceof AbstractBlock)) { continue; } if ($item->endsWithBlankLine() && $item !== $this->lastChild()) { $this->tight = false; break; } foreach ($item->children() as $subItem) { if ($subItem instanceof AbstractBlock && $subItem->endsWithBlankLine() && ($item !== $this->lastChild() || $subItem !== $item->lastChild())) { $this->tight = false; break; } } } } public function isTight(): bool { return $this->tight; } public function setTight(bool $tight): self { $this->tight = $tight; return $this; } } 